import{_ as e,o as t,c as l,aj as o}from"./chunks/framework.DNJ2HNkG.js";const _=JSON.parse('{"title":"家庭万兆局域网记录","description":"","frontmatter":{"title":"家庭万兆局域网记录","date":"2020-6-6 19:18:0","category":"Home","tags":["Home"]},"headers":[],"relativePath":"posts/家庭万兆局域网记录.md","filePath":"posts/家庭万兆局域网记录.md","lastUpdated":1783047625000}'),p={name:"posts/家庭万兆局域网记录.md"};function r(a,i,S,A,E,n){return t(),l("div",null,[...i[0]||(i[0]=[o('<p>来杭州后，为了将USRP-2943也就是USRP X310一套用起来，家用一整套基本都更新换代了，这里简单记录下：</p><p><img src="https://raw.githubusercontent.com/white-alone/blog_img/master/%E5%AE%B6%E5%BA%AD%E4%B8%87%E5%85%86%E5%B1%80%E5%9F%9F%E7%BD%91%E8%AE%B0%E5%BD%95/%E8%87%AA%E5%BB%BA%E5%AE%B6%E7%94%A8%E5%A4%9A%E5%AA%92%E4%BD%93%E4%B8%AD%E5%BF%83.png" alt=""></p><ol><li><p>入口是光猫，之后接到3865U的软路由，跑的ESXi，虚拟了自己编译的LEDE用来做网关，包括梯子、内网穿透、广告过滤等等插件。还有一个RouterOS，用于DHCP，LEDE的DHCP不如ROS的好用。</p></li><li><p>软路由后面就是Mikrotik的CRS309-1G-8S+IN桌面万兆交换机，安静好用，系统切换到了SwOS，速度杠杠的。</p></li><li><p>WIFI用的是Netgear的Orbi路由套件， 以后应该会换到WIFI 6的AP+AC或者Mesh路由，ASUS的TUF AX3000好像不错，如果要性价比就华为的AX3Pro。</p></li><li><p>NAS用的QNAP TS-873，里面2个PCI-E插槽，一个插了一块丽台P600的显卡用于8K解码，一块是intel X520万兆网卡，1块SSD装系统和应用，剩下的是8T和12T的西数企业盘。自从群晖丢过资料后，就切换到了QNAP，再后面用DS1819被垃圾智障的虚拟化、收费的docker还没有nat，就再不用群晖了，太垃圾。至于照片自动同步备份、视频在线解码播放、文件共享、TimeMachine等，那是NAS的基本功能，做私有云盘妥妥的。QNAP自带的内网穿透速度一般，所以我安装了zerotier做补充。</p></li><li><p>NAS的虚拟化和Docker做的很棒</p></li></ol><ul><li>跑了Gogs做私人git</li><li>跑了个Ubuntu做Linux本地镜像源，因为经常要重装系统部署环境，每次从公网apt下载太慢了，直接本地部署一个，万兆局域网秒下</li><li>跑了个Win7运行各种PT、BT、百度云、腾讯云、迅雷等下载器</li><li>跑了个开源leanote蚂蚁笔记服务器，做私人笔记</li><li>跑了个couchdb的docker，给小书匠做数据库同步【小书匠是一个非常好用的markdown编辑器，功能非常齐全，兼容各种blog发布、图床，很方便，如果觉得好用要注册VIP可以加上我的邀请码 71_orujhl】</li></ul><ol start="6"><li><p>家用Sever当前是自己DIY的，主板ASUS Z10PA-D8，CPU只上了一路 Xeon E5-2682 v4 16核32线程，内存2x32合计64G，运行ESXi虚拟出各种开发、调试、测试的系统。以后按需要再扩充第二路CPU和内存。网卡也是intel X520万兆网卡，WIFI是PCI-E直通AX200，还有一块SDR卡也是PCI-E直通。</p></li><li><p>主力机是ROG X570-E配AMD R7-3800X，现在AMD确实香。</p></li><li><p>UPS用的ADPT的网络UPS，QNAP和ESXi都能通过网络关联上，停电自动关机，确保数据不丢失。</p></li><li><p>SDR主要用SDR卡、USRP-2943和USRP-2920，偶尔也用USRP B210、B205mini-i和BladeRF。</p></li><li><p>内网穿透用的ZeroTier，在自己的阿里云服务器上做做了个Moon，只可惜是1M小水管，凑合用吧。阿里云的VPS带宽还是很昂贵的。</p></li></ol>',5)])])}const P=e(p,[["render",r]]);export{_ as __pageData,P as default};
